+package main
+
+import (
+	"bytes"
+	"image"
+	"image/png"
+	"math"
+	"os"
+	"path/filepath"
+	"testing"
+)
+
+func TestRunMP3E2E(t *testing.T) {
+	input := testdataPath(t, "sine.mp3")
+	outDir := t.TempDir()
+	outPath := filepath.Join(outDir, "spectro.jpg")
+
+	stdout := &bytes.Buffer{}
+	stderr := &bytes.Buffer{}
+	exit := run([]string{
+		"--width", "320",
+		"--height", "180",
+		"--start", "0.2",
+		"--duration", "0.5",
+		"--style", "magma",
+		"--output", outPath,
+		input,
+	}, bytes.NewReader(nil), stdout, stderr)
+	if exit != 0 {
+		t.Fatalf("exit %d stderr=%s", exit, stderr.String())
+	}
+	if stdout.String() == "" {
+		t.Fatalf("expected stdout output")
+	}
+	info, err := os.Stat(outPath)
+	if err != nil {
+		t.Fatalf("missing output: %v", err)
+	}
+	if info.Size() == 0 {
+		t.Fatalf("empty output")
+	}
+
+	file, err := os.Open(outPath)
+	if err != nil {
+		t.Fatalf("open output: %v", err)
+	}
+	defer func() { _ = file.Close() }()
+	img, _, err := image.Decode(file)
+	if err != nil {
+		t.Fatalf("decode image: %v", err)
+	}
+	if img.Bounds().Dx() != 320 || img.Bounds().Dy() != 180 {
+		t.Fatalf("size mismatch")
+	}
+	if flatImage(img) {
+		t.Fatalf("image appears flat")
+	}
+}
+
+func TestRunFromStdinPNG(t *testing.T) {
+	outDir := t.TempDir()
+	outPath := filepath.Join(outDir, "spectro.png")
+
+	wav := makeWAV([]int16{0, 2000, -2000, 0, 1000, -1000}, 44100, 1)
+	stdout := &bytes.Buffer{}
+	stderr := &bytes.Buffer{}
+	exit := run([]string{
+		"--format", "png",
+		"--output", outPath,
+		"-",
+	}, bytes.NewReader(wav), stdout, stderr)
+	if exit != 0 {
+		t.Fatalf("exit %d stderr=%s", exit, stderr.String())
+	}
+	file, err := os.Open(outPath)
+	if err != nil {
+		t.Fatalf("open output: %v", err)
+	}
+	defer func() { _ = file.Close() }()
+	if _, err := png.Decode(file); err != nil {
+		t.Fatalf("decode png: %v", err)
+	}
+}
+
+func TestRunVersion(t *testing.T) {
+	stdout := &bytes.Buffer{}
