+	}
+	stdout := &bytes.Buffer{}
+	stderr := &bytes.Buffer{}
+	exit := run([]string{"--format", "png", input}, bytes.NewReader(nil), stdout, stderr)
+	if exit != 0 {
+		t.Fatalf("exit %d stderr=%s", exit, stderr.String())
+	}
+	outPath := filepath.Join(dir, "input.png")
